import{_ as r,o as n,c as o,a7 as s}from"./chunks/framework.BgApuQ2e.js";const e="/images/second-presidential-debate/pinit_fg_en_rect_gray_20.png",c=JSON.parse('{"title":"The Second Presidential Debate","description":"","frontmatter":{"title":"The Second Presidential Debate","titleZh":"第二场总统辩论","date":"2016-10-10T00:00:00.000Z","originalUrl":"https://waitbutwhy.com/2016/10/second-presidential-debate.html","slug":"second-presidential-debate"},"headers":[],"relativePath":"posts/second-presidential-debate.md","filePath":"posts/second-presidential-debate.md","lastUpdated":1782886257000}'),p={name:"posts/second-presidential-debate.md"};function g(a,t,i,d,l,h){return n(),o("div",null,[...t[0]||(t[0]=[s('<h1 id="第二场总统辩论-·-the-second-presidential-debate" tabindex="-1">第二场总统辩论 · The Second Presidential Debate <a class="header-anchor" href="#第二场总统辩论-·-the-second-presidential-debate" aria-label="Permalink to &quot;第二场总统辩论 · The Second Presidential Debate&quot;">​</a></h1><blockquote><p>原文:<a href="https://waitbutwhy.com/2016/10/second-presidential-debate.html" target="_blank" rel="noreferrer">https://waitbutwhy.com/2016/10/second-presidential-debate.html</a> · 2016-10-10</p></blockquote><p>万一你错过了,我特意把<a href="https://www.youtube.com/watch?v=ooShpws3Dik" target="_blank" rel="noreferrer">第二场总统辩论</a>全程逐字记录了下来。事情是这样的:</p><p><strong>Martha Raddatz:</strong> 你好我是 Martha。</p><p><strong>Anderson Cooper:</strong> 我是 Anderson。今晚我们俩是主持人。</p><p><strong>Martha:</strong> 提醒一下所有现场观众,你们基本上就是道具,辩论期间请保持安静。辩论形式是由观众提问。我们从一位叫 Patrice Brock 的女士开始。</p><p>***观众提问:*<em>谢谢,晚上好。上一场总统辩论按照电视家长指南评级的话,大概可以评为 MA——成人观众级。考虑到老师们把观看总统辩论作为学生的家庭作业,你们觉得自己在为当今的青少年树立恰当且积极的行为榜样吗?</em></p><p><strong>Clinton:</strong> 我想做各种各样的事。我想做好事。Patrice,你和我一起,没有什么办不到的。我想和所有族裔的人一起共事。我想治愈这个国家。让它变得更好。为了你,为了我,为了全人类。为了我们的孩子。还有孙辈。</p><p><strong>Trump:</strong> 这个国家正在完蛋。医保成本节节攀升。我们让伊朗再次伟大了。我们在贸易上被宰得死死的——去年 8000 亿美元的逆差。我们要签伟大的贸易协议。我们要恢复法律和秩序。你听说今天那些被枪击的警察了吗?我们需要正义。我想解决城市里黑人的问题。我想解决拉丁裔、西班牙裔等等的问题。让他们再次伟大。让美国再次伟大。</p><p><strong>Anderson Cooper:</strong> 你俩没有任何一个人有一丁点回答那个问题。你们俩根本就是无视 Patrice。不过话说回来,我也不关心 Patrice。我们来聊聊那些录音吧。Donald,你说你未经同意亲吻女性。抓她们的下体。这绝对绝对就是性侵。你吹嘘自己性侵女性。这是真实发生过的事。是一件真实存在的事。</p><p><strong>Trump:</strong> 错。我看你根本不懂什么叫性侵。抓女性的下体是更衣室闲聊。性侵女性是抓她们的下体。抓女性下体这事我很抱歉。我从来没干过。而且你怎么能说这比 ISIS 还糟糕?ISIS 砍了几千人的头。你怎么能把我和 ISIS 相提并论?他们把人装在钢笼里淹死。这种事我一次都没干过。Anderson 你怎么敢这么说。明天就等着看美国人民怎么评价你说 ISIS 不算个事这句话。你想想我们的敌人看到这里发生的一切会怎么说。是,那就是更衣室闲聊。是,我讨厌那种话。我有对付 ISIS 的高超战略。我会击败 ISIS。</p><p><strong>Anderson:</strong></p><p><strong>Trump:</strong></p><p><strong>Anderson:</strong> 好吧,那你到底有没有性侵过女性?</p><p><strong>特朗普:</strong> 没有人比我更尊重女性。没有人。罗杰斯先生都比不上我。苏珊·B·安东尼 (Susan B. Anthony) 也比不上我。没有人。对一个已婚女人下手就是尊重的表现。每个父母都希望自己的女儿嫁给我这样的人。所有女人都尊重我。</p><p><strong>安德森:</strong> 但是就字面意义上——你有没有性侵过女性?</p><p><strong>特朗普:</strong> 只用我的尊重侵犯过。我们要建一堵墙。我们要有边境。人们正从中东涌进我们的国家来抓美国女人的下体。我们要让美国重新安全起来。我们要让美国再次伟大。我们要让美国重新安全起来。我们要让美国重新富有起来。中国。</p><p><strong>安德森:</strong> 克林顿国务卿,您想回应一下吗?</p><p><strong>克林顿:</strong> 里根。布什。艾森豪威尔。他们抓过女人的胳膊吗?抓过。抓过手吗?可能有。搂过肩膀吗?当然。但是抓下体?我不这么认为。唐纳德·特朗普是个坏人。他是个啥啥主义者。他就是《校园风云》(<em>School Ties</em>) 里的马特·达蒙。他是《漫漫回家路》(<em>The Long Walk Home</em>) 里的那个叔叔。他是《为奴十二年》(<em>12 Years a Slave</em>) 里那个刻薄的奴隶主。他是《虎胆龙威》(<em>Die Hard</em>) 里那个德国主犯。他是《咒怨》(<em>The Grudge</em>) 里的那个女人。他是布鲁托 (Bluto)。他是贾方 (Jafar)。他是小丑。他是异鬼。他是食死徒。他是僵尸。他是鬼魂。而我呢,想要组建一个由各种肤色的人手拉手围成的巨大圆圈,一直环绕整个地球。你能用风的所有色彩作画吗?</p><p><strong>特朗普:</strong> 30 年了。这位女士治理这个国家 30 年了,而我从来没有,任何其他人也从来没有,成为过一个由各种肤色的人手拉手围绕地球的圆圈的一部分。这个该死的女人搞了 30 年,她连用颜料画过任何东西都没有,更别说风的色彩了。</p><p><strong>玛莎:</strong> 好吧,回到你的更衣室性侵话题。你说过这场竞选改变了你——尽管你在那段视频里 59 岁时明显是个性侵犯,你现在已经变好了。这是真的吗?</p><p><strong>特朗普:</strong> 玛莎——我不知道我还能说得多清楚。我讲的是详尽的性侵故事,包含具体的日期、名字和身体部位。这就是经典的更衣室对话。每个男人都会跟其他男人讲他以前性侵的详细故事,包含具体的日期、名字和身体部位。你不知道是因为你不在场——但只要男人们单独在一起,他们就会聊自己以前的性侵经历。这不代表他们真的侵犯过谁。除非他们是比尔·克林顿。比尔·克林顿是个真他妈的坏家伙。比尔·克林顿告诉我,他曾经在一家塔可钟餐厅的杂物间里掐着一个女员工的脖子把她按倒并跟她发生了关系。比尔·克林顿还告诉我,他跟切尔西的三个闺蜜玩过 4P,当时切尔西就睡在楼上。希拉里错过了那次,因为她正忙着嘲笑一个 12 岁的强奸受害者,巧的是那位受害者现在就坐在那边。</p><p><strong>玛莎:</strong> 干得漂亮。希拉里?</p><p><strong>克林顿:</strong> 这个问题我让米歇尔·奥巴马来回答。她说过:「当有人提到你老公在塔可钟餐厅的杂物间把一个员工按住脖子并跟她发生性关系那件事时,你要保持高姿态。」还有,你侮辱了一位穆斯林战争英雄的父母,说一位拉丁裔法官天生有偏见,嘲笑了一位残疾记者,还说奥巴马是外国人。</p><p><strong>特朗普:</strong> 前三条,行吧。但<em>你</em>才是那个说奥巴马是外国人的人。还有,米歇尔·奥巴马公开说过你是史上最差。还有,你作弊击败了伯尼·桑德斯。还有,你删了33,000封邮件,你个鬼鬼祟祟的混蛋。等我当上元首,我就雇一个特别检察官来追查你。</p><p><strong>克林顿:</strong> 他什么事都在撒谎,全都在我网站上,我们该庆幸这个不定时炸弹没掌管这个国家的法律。</p><p><strong>特朗普:</strong> 因为那样你就在坐牢了。</p><p><strong>观众:</strong> 哦卧槽!</p><p><strong>安德森:</strong> 我们提醒观众别再当个人渣了。</p><p><strong>玛莎:</strong> 但说真的,希拉里——你那些邮件是怎么回事,你个鬼鬼祟祟的混蛋。</p><p><strong>克林顿:</strong> 那是个错误。我写了33,000封关于切尔西婚礼和瑜伽课的邮件,我不该删掉的。现在让我们进入观众提问环节。</p><p><strong>特朗普:</strong> 当然了——为了转移这个问题什么都干得出来,你这个奸诈的泼妇。</p><p><strong>克林顿:</strong> 为了转移你竞选活动的注意力什么都干得出来,你这个不可压缩的精液喇叭。</p><p><strong>安德森:</strong> <em>够</em>了。现在让我们继续这场市民大会闹剧,进入第二个观众问题。</p><p><strong>特朗普:</strong> 一如既往。</p><p><strong>安德森:</strong> 啊?</p><p><strong>特朗普:</strong> 你从来不问希拉里邮件的事。你从来不给我时间。你根本不在乎我。这是一对三。</p><p><strong>安德森:</strong> 才不是。就一点点。下一个问题。</p><p><em><strong>观众提问:</strong></em> <em>奥巴马医改让东西更贵了,而不是更便宜。你要怎么把医疗成本降下来?</em></p><p><strong>特朗普:</strong> 那么——</p><p><strong>安德森:</strong> 不,这里希拉里应该先说。</p><p><strong>克林顿:</strong> 不没事我更想第二个说。</p><p><strong>特朗普:</strong> 不没事你先说。</p><p><strong>克林顿:</strong> 不你先。</p><p><strong>特朗普:</strong> 不你先。</p><p><strong>克林顿:</strong> 不你先。</p><p><strong>特朗普:</strong> 不你先。</p><p><strong>克林顿:</strong> 不你先。</p><p><strong>特朗普:</strong> 不你先。</p><p><strong>克林顿:</strong> 奥巴马医改很好。</p><p><strong>特朗普:</strong> 奥巴马医改是场灾难。</p><p><strong>安德森:</strong> 希拉里,你老公比尔也说过奥巴马医改是场灾难。</p><p><strong>克林顿:</strong> 不他没说过。</p><p><strong>特朗普:</strong> 伯尼·桑德斯说希拉里判断力很差。</p><p><strong>安德森:</strong> 我们继续。观众提问。</p><p><em><strong>观众提问:</strong></em> <em>我是穆斯林。你怎么帮我不被仇恨犯罪?</em></p><p><strong>特朗普:</strong> 被仇恨犯罪针对是很可耻。但我们有个问题。就是你们不告诉我们其他穆斯林什么时候要杀我们。在圣贝纳迪诺(San Bernardino),有穆斯林杀了我们,你们没告诉我们。如果你们告诉了我们,我们本可以阻止的。我觉得你们也没告诉过我们奥兰多的事,或者 9/11 那件事。我知道这一点是因为,如果你告诉过我们 9/11 的事,我很确定你会出名,而出名的人不会来参加市政厅会议。</p><p><strong>克林顿:</strong> 你是穆斯林。我是穆斯林。为国捐躯、被唐纳德憎恨的可汗上尉 (Captain Khan),是穆斯林。</p><p><strong>玛莎:</strong> 嘿唐纳德,还记得你的穆斯林禁令吗?我们来聊聊。</p><p><strong>特朗普:</strong> 我爱可汗上尉。我把他的名字纹在了下背部。一位美国英雄。被希拉里发动伊拉克战争害死了,那也是我讨厌的另一件事。</p><p><strong>玛莎:</strong> 他妈的——哥们——不行。回答问题。</p><p><strong>特朗普:</strong> 谁把你搞得这么刻薄?是你父母吗?</p><p><strong>玛莎:</strong> 穆斯林禁令还有效吗?</p><p><strong>特朗普:</strong> 希拉里想把美国和叙利亚合并成一个国家。她想把难民数量从 1 万增加到 6.5 万。</p><p><strong>玛莎:</strong> 希拉里你他妈搞什么?</p><p><strong>克林顿:</strong> 那张海滩上穿着小运动鞋的四岁死去男孩的照片。</p><p><strong>玛莎:</strong> 完全懂。</p><p><strong>克林顿:</strong> 另外,唐纳德真的想禁止一整个主流宗教的人进入美国。我们能不能就这一点稍微反思一下?还有,是他发动了伊拉克战争,不是我。</p><p><strong>特朗普:</strong> 我反对伊拉克战争。</p><p><strong>克林顿:</strong> 你没有。</p><p><strong>特朗普:</strong> 我反对过。</p><p><strong>克林顿:</strong> 你没有。</p><p><strong>特朗普:</strong> 我反对过。</p><p><strong>克林顿:</strong> 你没有。</p><p><strong>特朗普:</strong> 我反对过。伯尼·桑德斯 (Bernie Sanders) 说希拉里·克林顿判断力差。</p><p><strong>玛莎:</strong> 好,下一个问题。希拉里,你在一次秘密演讲中说政客在某些问题上需要有公开立场和私下立场。政客两面派可以吗?</p><p><strong>克林顿:</strong> 那是亚伯拉罕·林肯说的,不是我。更重要的是,特朗普痴迷于普京。</p><p><strong>特朗普:</strong> 我没有痴迷于普京。我交了税。我做了抵扣。希拉里的朋友们也做了抵扣。希拉里跟有钱人是朋友。</p><p><strong>安德森:</strong> 什么鬼?好吧既然聊到这儿了:</p><p><em><strong>观众提问:</strong> 你将如何确保富裕的美国人缴纳他们应缴的税款?</em></p><p><strong>特朗普:</strong> 好,我要做的第一件事是(顺便说一下,首批条款之一是(顺便说一下你知道我竞选的时候放弃了很多东西因为我要改税法(顺便说一下你知道她多年前就可以这么做但她没有因为她的富人朋友不想让她这么做(整整他妈的 30 年,各位——跟这位女士打了 30 年交道什么都没变——什么都永远不会变)))) 是取消附带权益条款 (carried interest)。我还要给富人减税,顺便说一下希拉里要给你们加税,那简直是灾难。这个国家没有增长。这个国家正在完蛋。中国正在把我们搞死。</p><p><strong>克林顿:</strong> 又是这个混蛋的满嘴谎话。他要给超级富豪减税,给中产阶级加税。</p><p><strong>特朗普:</strong> 是啊,她要堵住企业漏洞——只要不是她那些富豪朋友在用的漏洞。而且,伯尼·桑德斯 (Bernie Sanders) 都说她判断力差。整整他妈的 30 年了,各位,这位女士。30——</p><p><strong>克林顿:</strong> 30 年个屁,唐纳德。30 年里我搞了 400 项立法。</p><p><strong>特朗普:</strong> 才没有。</p><p><strong>玛莎:</strong> 下一个问题。阿勒颇 (Aleppo) 一片狼藉。有什么想法?</p><p><strong>克林顿:</strong> 我们要对俄罗斯和阿萨德 (Assad) 强硬起来,拯救阿勒颇。</p><p><strong>特朗普:</strong> 拯救阿勒颇的谁,那些叛军吗?他们比阿萨德还烂。我们要打 ISIS。</p><p><strong>玛莎:</strong> 可是特朗普先生,你的竞选搭档同意希拉里的看法。他甚至想动用军事力量对抗俄罗斯和阿萨德。</p><p><strong>特朗普:</strong> 那他傻。我们该打的是 ISIS。我比将军们还懂 ISIS。</p><p><strong>克林顿:</strong> 你他妈才不懂。</p><p><strong>安德森:</strong> 观众提问。</p><p><em><strong>观众提问:</strong></em> <em>你相信你能成为一位为全体美国人民尽心尽力的总统吗?</em></p><p><strong>特朗普:</strong> 我想帮助所有美国人。黑人美国人。拉美裔 Americanos personas。印第安酋长们。我们的城市是场灾难。我们的教育是场灾难。贫困是场灾难。自然灾害是场灾难。她说过什么「一筐可悲之人」。</p><p><strong>克林顿:</strong> 我想帮助所有美国人——可悲的和不可悲的。我跟一个埃塞俄比亚小孩聊过,他害怕特朗普。</p><p><strong>安德森:</strong> 但那个「可悲之人」的事到底怎么回事?</p><p><strong>克林顿:</strong> 我说的是实话,只是不该公开说。</p><p><strong>特朗普:</strong> 她心里充满了巨大的仇恨。她心里的仇恨是场灾难。</p><p><strong>安德森:</strong> 那么唐纳德,还记得那天你半夜爬起来,凌晨三点狂喷一个不知从哪冒出来的女人,叫大家去看她的性爱录像带吗?那……那是怎么回事?</p><p><strong>特朗普:</strong> 那个骚货。</p><p><strong>安德森:</strong> 让我们进入下一个问题,提问人叫肯尼斯·骨头 (Kenneth Bone)。</p><p><em><strong>观众提问:</strong> 我是肯尼斯·骨头。我是肯尼斯·骨头,我穿着这件毛衣。还有这是我的胡子。</em></p><p><strong>安德森:</strong> 就这?就这?</p><p><em><strong>肯尼斯·骨头:</strong> 你们的能源政策是什么?</em></p><p><strong>特朗普:</strong> 煤炭。煤炭是未来。中国正在把我们干趴。中国在向我们倾销钢铁。</p><p><strong>克林顿:</strong> 中国在往你那张烂脸上倾销钢铁。你买了一堆中国钢材。气候变化是真的。煤炭是真的。真的东西就是真的东西。</p><p><strong>玛莎:</strong> 好了最后一个问题,谢天谢地他妈的。</p><p><em><strong>观众提问:</strong> 让你们俩互相说点好话感觉会挺搞笑挺有趣的。</em> <em>开始吧。</em></p><p><strong>克林顿:</strong> 他的孩子们不算烂人。不知怎么的。</p><p><strong>特朗普:</strong> 这婊子挺能打。</p><h2 id="安德森-我要向观看本场辩论的-7-9-亿观众表达感谢和歉意。晚安。" tabindex="-1"><strong>安德森:</strong> 我要向观看本场辩论的 7.9 亿观众表达感谢和歉意。晚安。 <a class="header-anchor" href="#安德森-我要向观看本场辩论的-7-9-亿观众表达感谢和歉意。晚安。" aria-label="Permalink to &quot;**安德森:** 我要向观看本场辩论的 7.9 亿观众表达感谢和歉意。晚安。&quot;">​</a></h2><p>如果你喜欢 Wait But Why,请订阅我们的**<a href="https://newsletter.waitbutwhy.com/join" target="_blank" rel="noreferrer">邮件列表</a>**,新文章发布时我们会发送给你。</p><h2 id="想要支持-wait-but-why-请访问我们的-patreon-页面。" tabindex="-1">想要支持 Wait But Why,请访问我们的 <strong><a href="https://patreon.com/waitbutwhy" target="_blank" rel="noreferrer">Patreon 页面</a></strong>。 <a class="header-anchor" href="#想要支持-wait-but-why-请访问我们的-patreon-页面。" aria-label="Permalink to &quot;想要支持 Wait But Why,请访问我们的 **[Patreon 页面](https://patreon.com/waitbutwhy)**。&quot;">​</a></h2><p><strong>如果你喜欢这篇,你大概也会喜欢:</strong></p><p><strong><a href="https://waitbutwhy.com/2013/10/why-procrastinators-procrastinate.html" target="_blank" rel="noreferrer">为什么拖延症患者会拖延</a></strong></p><p><strong><a href="https://waitbutwhy.com/2015/07/why-im-always-late.html" target="_blank" rel="noreferrer">为什么我总是迟到</a></strong></p><p><strong><a href="https://waitbutwhy.com/2014/02/pick-life-partner.html" target="_blank" rel="noreferrer">如何挑选人生伴侣</a></strong></p><p><strong><a href="https://waitbutwhy.com/2014/12/10-types-odd-friendships-youre-probably-part.html" target="_blank" rel="noreferrer">你八成身处其中的 10 种奇葩友谊</a></strong></p><p><a href="https://twitter.com/share" target="_blank" rel="noreferrer">Tweet</a></p><p><a href="//www.pinterest.com/pin/create/button/?url=https://waitbutwhy.com/2016/10/second-presidential-debate.html&amp;description=The%20Second%20Presidential%20Debate" target="_blank" rel="noreferrer"><img src="'+e+'" alt=""></a></p>',120)])])}const b=r(p,[["render",g]]);export{c as __pageData,b as default};
